void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec3 sample = texture( sampler_main, vUv);
vec3 p = sample;
sample =pow( p,0.45);
p = 1-mix(vec3(1,1,0),vec3(0,0,1),sample.y)*2;
p *= vec3(1,0,0) - sample.x;
p = clamp01(p);
